head.script:
/**
 * 화 면 명 : 근무복신청현황
 * 메뉴경로 : 공통/총무업무/피복관리/
 * ASIS경로 : /dongwon-debis-engine/src/main/webapp/cm/bc/affairs/zz_770_02_03b.jsp
 * 작 성 자 : 정승혜
 * 작 업 일 : 2025-10-20
 * 수정이력  :
 *    - 2025-10-20      정승혜    최초작성
 *    - 2025-11-26      정승혜    준수사항 적용
 *    - 2025-12-30      정승혜    기타수정
 *    - 2026-01-19      정승혜    submitdone 조건수정
 * 메모 : 
 */

// strCurDate 사용되는곳 없음
/* 
	DDate sDate = new DDate();
	String strCurDate = sDate.getDate("");	
	String strYm = strCurDate.substring(0,6);
*/
scwin.tab_Gb = "";

//-------------------------------------------------------------------------
// 화면로딩시 Default 값 Setting
//-------------------------------------------------------------------------
scwin.onpageload = function() {
    // getCodeList
    const codeOptions = [
        { grpCd : "DRS_L", compID : "lc_deptCd" },
    ];
    $c.data.setCommonCode(codeOptions);

    const param= [
        {
            method: "getLuxeComboData",
            param1: "SheathMgntEBC",
            param2: "retrieveSheathPostSeqCd",
            compID: "lc_postSeq"
        }
    ];
    $c.data.setGauceUtil(param);

    scwin.f_CreateSearchHeader();
	//scwin.f_ViewTab(0);
	scwin.f_CondInit();
};

// 공통코드가 셋팅이 되고 scwin.ondataload 이벤트가 호출
scwin.ondataload = function() { 
    dlt_commonCodeDRS_L.sort("cd", 0);
}
//-------------------------------------------
// Tab Display 
//-------------------------------------------
scwin.f_ViewTab = function() {
    //tabControl 사용
};

//-------------------------------------------
// 조건 초기화
//-------------------------------------------
scwin.f_CondInit = function() {
    $c.gus.cfInitObjects(tbl_search);
    lc_postSeq.setSelectedIndex(0);
};

//-------------------------------------------------------------------------
// 조회조건 헤더 
//-------------------------------------------------------------------------
scwin.f_CreateSearchHeader = function() {
    // DataSet의 Header 정보 생성(TODO:TOBE 데이터맵으로 셋팅하므로 필요없음)
};

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function (e) {
    let ret = await $c.gus.cfValidate([lc_postSeq]);
    if (!ret){
        return;
    }

    scwin.tab_Gb = tac_tabControl1.getSelectedTabIndex();
    if(scwin.tab_Gb == "0"){ 			// 신청현황(지사별)
		$c.sbm.execute(sbm_retrieve);
	}else if(scwin.tab_Gb == "1"){  	//신청현황(Summary)
        $c.sbm.execute(sbm_retrieve2);
	}else if(scwin.tab_Gb == "2"){  	//신청현황(SIZE별)
        $c.sbm.execute(sbm_retrieve3);
	}
};

//-------------------------------------------
// tab_Gb에 따라 ds_cond, ds 세팅
//-------------------------------------------
scwin.f_dsSetting = function() {
    // 서브미션 분리함
};

//-------------------------------------------
//  높이조절
//-------------------------------------------
scwin.f_GrdHeiht = function() {

};

//-------------------------------------------
//  엑셀다운
//-------------------------------------------
// 엑셀다운 2+4+8+16
scwin.f_Excel = function() {
    const options = {
        fileName : "지사별신청현황.xlsx", 
        sheetName : "지사별신청현황",
        type : 1,

    };
    $c.data.downloadGridViewExcel(gr_out, options);
};

scwin.f_Excel2 = function() {
    const options = {
        fileName : "신청현황Summary.xlsx", 
        sheetName : "신청현황Summary",
        type : 1,
        //
    };
    $c.data.downloadGridViewExcel(gr_out2, options);    
};

scwin.f_Excel3 = function() {
    const options = {
        fileName : "SIZE별신청현황.xlsx", 
        sheetName : "SIZE별신청현황",
        type : 1,

    };
    $c.data.downloadGridViewExcel(gr_out3, options);    
};

// 서브미션
scwin.sbm_retrieve_submitdone = function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return;
    totalRows.setValue(ds_out.getRowCount());
    if (ds_out.getRowCount() == 0) {
        $c.gus.cfAlertMsg(MSG_CM_WRN_002); 
    } else {
        $c.gus.cfGoPrevPosition(gr_out,0); 
    }
};

// 서브미션
scwin.sbm_retrieve2_submitdone = function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return;
    totalRows2.setValue(ds_out2.getRowCount());
    if (ds_out2.getRowCount() == 0) {
        $c.gus.cfAlertMsg(MSG_CM_WRN_002); 
    } else {
        $c.gus.cfGoPrevPosition(gr_out2,0); 
    }
};

// 서브미션
scwin.sbm_retrieve3_submitdone = function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return;
    totalRows3.setValue(ds_out3.getRowCount());
    if (ds_out3.getRowCount() == 0) {
        $c.gus.cfAlertMsg(MSG_CM_WRN_002); 
    } else {
        $c.gus.cfGoPrevPosition(gr_out3,0); 
    }
};

// 신청현황(SIZE별) 그리드 데이터 0일때 공란 표출
scwin.displayFm = function(data) {
    return $c.gus.decode(data,0,"",data);
};
